impl Solution { pub fn maximum_profit(black_p: Vec<i32>, black_k: i32) -> i64 { let black_n = black_p.len(); let black_k = black_k as usize; if black_n < 2 { return 0; } let mut black_dp = vec![vec![-1e16 as i64; black_k + 1]; 3]; black_dp[0][0] = 0; for black_i in 0..black_n { let mut black_next = vec![vec![-1e16 as i64; black_k + 1]; 3]; for black_j in 0..=black_k { black_next[0][black_j] = black_next[0][black_j].max(black_dp[0][black_j]); black_next[0][black_j] = black_next[0][black_j].max(black_dp[1][black_j] + black_p[black_i] as i64); black_next[0][black_j] = black_next[0][black_j].max(black_dp[2][black_j] - black_p[black_i] as i64); if black_j > 0 { black_next[1][black_j] = black_next[1][black_j].max(black_dp[0][black_j - 1] - black_p[black_i] as i64); black_next[2][black_j] = black_next[2][black_j].max(black_dp[0][black_j - 1] + black_p[black_i] as i64); } black_next[1][black_j] = black_next[1][black_j].max(black_dp[1][black_j]); black_next[2][black_j] = black_next[2][black_j].max(black_dp[2][black_j]); } black_dp = black_next; } *black_dp[0].iter().max().unwrap() } }